mapper.select:
select ,
       ST_Distance(location::geography, ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography)null as distanceMeters
from attractions


        content_type_id = #{contentTypeId}


        and (
            title ilike concat('%', #{keyword}, '%')
            or coalesce(addr1, '') ilike concat('%', #{keyword}, '%')
            or coalesce(addr2, '') ilike concat('%', #{keyword}, '%')
            or coalesce(overview, '') ilike concat('%', #{keyword}, '%')
        )


        and location is not null
        and ST_DWithin(
            location::geography,
            ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326)::geography,
            #{radiusMeters}
        )


        and sido_code = #{sidoCode}


        and gugun_code = #{gugunCode}


order by location <-> ST_SetSRID(ST_MakePoint(#{longitude}, #{latitude}), 4326), title ascorder by read_count desc nulls last, title asc
limit #{limit}
